text:
{
  "formal_minutes": {
    "decisions": [
      {
        "id": "D1",
        "item": "공개 릴리스 목표일을 스모크 테스트 통과 시 금요일 15:00 KST로 확정."
      },
      {
        "id": "D2",
        "item": "`smoke-theme-pack.mjs`의 `packageName` mismatch 대응은 스크립트를 무시하지 않는다. 먼저 패키지 config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 고려한다."
      }
    ],
    "rejected_proposals": [
      {
        "id": "R1",
        "item": "Hara의 ‘`packageName` mismatch를 무시하도록 스크립트 변경’ 제안은 반려됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "id": "S1",
        "item": "수요일(Wednesday) 공개 릴리스는 내부 stretch goal로만 유지."
      }
    ],
    "non_decisions": [
      {
        "id": "N1",
        "item": "README 설치 단계는 가능하면 목요일에 리뷰 대상이지만, 담당자 미지정으로 아직 확정되지 않음."
      },
      {
        "id": "N2",
        "item": "릴리스 노트에 수요일 stretch goal을 언급할지 여부는 미확정."
      },
      {
        "id": "N3",
        "item": "Hara의 tarball 경로 확인은 항목 자체는 확인되었으나 최종 마감 시점은 미정."
      }
    ],
    "risks": [
      {
        "id": "RK1",
        "item": "tarball 경로가 잘못되면 릴리스 지연 가능성."
      },
      {
        "id": "RK2",
        "item": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오도된 정보를 전달할 위험."
      }
    ],
    "open_questions": [
      {
        "id": "Q1",
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "id": "Q2",
        "item": "릴리스 노트에 내부 stretch goal(수요일 목표)을 명시할지 여부"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 금요일 10:00 KST까지 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정/진행예정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 실패 원인 정리 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정/진행예정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시하면 생성된 tarball 경로를 확인한다.",
      "due": "미정 (Minjun 결과 공유 후)",
      "status": "확정/진행예정",
      "source_certainty": "high"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 리뷰(목표: 목요일 가능 시)",
      "due": "목요일(가능 시)",
      "status": "보류(담당자 미확정)",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 테스트 결과 공유가 완료되는지",
      "결과 기반으로 Hara가 tarball 경로 확인을 수행했는지",
      "README 설치 단계 리뷰의 실제 소유자와 완료 상태",
      "릴리스 승인 권한자 확정 여부",
      "릴리스 노트에 수요일 stretch goal 반영 여부 최종 결정"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너명",
      "예산, 보안 사고, 실서비스 장애, 법무 승인 사실",
      "추가 owner 또는 추가 마감기한(메모에 없는 항목)",
      "패치/코드 변경의 세부 구현 내용(회의록 외부 근거 없음)"
    ]
  },
  "non_invention_rules": [
    "회의록에 명시되지 않은 고객/파트너, 예산, 보안 사고, 장애, 법률 승인 관련 사실은 추가하지 않는다.",
    "마감, 담당자, 결재권자 등은 원문에 명시된 항목만 사용한다.",
    "확정되지 않은 항목은 ‘미정/미확정’으로 표기하고 단정적으로 선언하지 않는다.",
    "내부 stretch goal(수요일)은 공개 목표와 분리해서 기록한다."
  ]
}
